class MyClass { 
  public:
    // The Constructor
    MyClass() { 
      cout << "Hello World!";
    }
};

int main() {
  MyClass myObj; // myObj's Constructor fires instantly here!
  return 0;
}

class Car { 
  public:
    string brand;
    // Parametrized Constructor
    Car(string x) { 
      brand = x;
    }
};

int main() {
  // Pass "BMW" directly via constructor parameters at creation
  Car myCar("BMW");

  cout << myCar.brand;
  return 0;
}
